import { useEffect, useState } from 'react';
import api from '../../services/api';
import ProveedorForm from './ProveedorForm';
import toast from 'react-hot-toast';

export default function ProveedorList() {
  const [proveedores, setProveedores] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchProveedores = async () => {
    try {
      const res = await api.get('/proveedores');
      setProveedores(res.data);
    } catch (error) {
      toast.error('Error al cargar proveedores');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProveedores();
  }, []);

  const handleDelete = async (id) => {
    if (window.confirm('¿Eliminar proveedor?')) {
      try {
        await api.delete(`/proveedores/${id}`);
        toast.success('Proveedor eliminado');
        fetchProveedores();
      } catch (error) {
        toast.error('Error al eliminar');
      }
    }
  };

  const handleEdit = (proveedor) => {
    setEditing(proveedor);
    setShowForm(true);
  };

  const handleFormClose = () => {
    setShowForm(false);
    setEditing(null);
    fetchProveedores();
  };

  if (loading) return <div>Cargando...</div>;

  return (
    <div>
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-2xl font-bold">Proveedores</h1>
        <button onClick={() => setShowForm(true)} className="bg-green-600 text-white px-4 py-2 rounded">Nuevo Proveedor</button>
      </div>
      <div className="overflow-x-auto">
        <table className="min-w-full bg-white border">
          <thead>
            <tr className="bg-gray-100">
              <th className="py-2 px-4 border">Nombre</th>
              <th className="py-2 px-4 border">RUC</th>
              <th className="py-2 px-4 border">Teléfono</th>
              <th className="py-2 px-4 border">Email</th>
              <th className="py-2 px-4 border">Acciones</th>
             </tr>
          </thead>
          <tbody>
            {proveedores.map(p => (
              <tr key={p.id}>
                <td className="py-2 px-4 border">{p.nombre}</td>
                <td className="py-2 px-4 border">{p.ruc}</td>
                <td className="py-2 px-4 border">{p.telefono}</td>
                <td className="py-2 px-4 border">{p.email}</td>
                <td className="py-2 px-4 border">
                  <button onClick={() => handleEdit(p)} className="text-blue-600 mr-2">Editar</button>
                  <button onClick={() => handleDelete(p.id)} className="text-red-600">Eliminar</button>
                 </td>
               </tr>
            ))}
          </tbody>
         </table>
      </div>
      {showForm && <ProveedorForm proveedor={editing} onClose={handleFormClose} />}
    </div>
  );
}
